+        id: 'swarm-123',
+        objective: 'Build API',
+        status: 'active',
+        topology: 'hierarchical',
+        agents: [
+          { id: 'agent-1', type: 'researcher', status: 'active' },
+          { id: 'agent-2', type: 'coder', status: 'working' },
