+    // Heavy operations (neural, github) need lower concurrency
+    const heavyTypes = ['neural', 'github', 'workflow'];
+    const hasHeavyOps = toolTypes.some((type) => heavyTypes.includes(type));
+
+    if (hasHeavyOps) {
