+    if (this.pool.length > 0) {
+      this.reused++;
+      return this.pool.pop();
+    }
+    this.allocated++;
+    return this.createFn();
+  }
+
+  release(obj) {
+    if (this.pool.length < this.maxSize) {
+      this.resetFn(obj);
+      this.pool.push(obj);
+    }
+  }
+
+  getStats() {
+    return {
+      poolSize: this.pool.length,
+      allocated: this.allocated,
+      reused: this.reused,
+      reuseRate: (this.reused / (this.allocated + this.reused)) * 100,
