+/**
+ * AsyncOperationQueue for managing concurrent operations
+ */
+class AsyncOperationQueue {
+  constructor(maxConcurrency = 10, timeout = 30000) {
+    this.maxConcurrency = maxConcurrency;
+    this.timeout = timeout;
+    this.running = 0;
+    this.queue = [];
+    this.results = new Map();
